$id=max(0,(int)($_GET['id']??0)); $token=(string)($_GET['token']??''); $row=findReceiptRecord($pdo,$id); $valid=false; $reason='Receipt not found.'; if($row){ $invoice=(string)($row['invoice_no'] ?? ''); $real=(string)($row['receipt_token'] ?? receiptVerificationToken($id,$invoice)); if(hash_equals($real,$token)){ if(strtotime((string)$row['created_at'].' +30 days') >= time()){ $valid=true; } else { $reason='This QR/receipt has expired after 30 days. Please contact mosque management for manual verification.'; } } else { $reason='Receipt token is invalid.'; } }
